"""从原版dashboard HTML提取数据，生成Pico CSS + ECharts升级版"""
import re, json, sys
from pathlib import Path

SRC = Path(__file__).parent / "dashboard_2026-05-19.html"
DST = Path(__file__).parent / "dashboard_2026-05-19_v2.html"

html = SRC.read_text(encoding="utf-8")

# 提取 KPI 数字
kpi_nums = re.findall(r'<div class="num">(\d+)</div>', html)
total, active_3d, silent_90, ball_ours, need_confirm, need_action = kpi_nums[:6] if len(kpi_nums) >= 6 else ["?","?","?","?","?","?"]

# 提取 MATRIX JSON
m = re.search(r'window\.MATRIX\s*=\s*(\{.*?\});\s*window\.KPI_DATA', html, re.DOTALL)
if not m:
    m = re.search(r'window\.MATRIX\s*=\s*(\{.*?\});\s*function', html, re.DOTALL)
matrix_json_str = m.group(1) if m else "{}"
matrix = json.loads(matrix_json_str)

# 提取 KPI_DATA JSON
m2 = re.search(r'window\.KPI_DATA\s*=\s*(\{.*?\});\s*function', html, re.DOTALL)
kpi_data = {}
if m2:
    try:
        kpi_data = json.loads(m2.group(1))
    except:
        pass

# 构建矩阵汇总: stage -> grade -> count
stages = ["需求探索","报价已发","谈判中","待付款","待发货","已发货/在途","已签收","售后","待返单"]
grades = ["S","A","B","C","D"]

matrix_counts = {}
for stage in stages:
    matrix_counts[stage] = {}
    for g in grades:
        matrix_counts[stage][g] = len(matrix.get(stage, {}).get(g, []))

# 构建完整矩阵 JSON (client list per cell)
matrix_full = matrix

# 为 ECharts 准备热力图数据
heatmap_data = []
for si, stage in enumerate(stages):
    for gi, g in enumerate(grades):
        cnt = matrix_counts[stage][g]
        if cnt > 0:
            heatmap_data.append([gi, si, cnt])

# ===================== 生成 HTML =====================
matrix_full_json = json.dumps(matrix_full, ensure_ascii=False)
kpi_full_json = json.dumps(kpi_data, ensure_ascii=False)

html_out = f'''<!DOCTYPE html>
