    --dot-grey: #bbb;
  }
  [data-theme="dark"] {
    --bg: #1a1a2e;
    --surface: #16213e;
    --surface-hover: #1a2744;
    --border: #2a2a4a;
    --text: #e0e0e0;
    --text-secondary: #888;
    --text-tertiary: #666;
    --shadow: 0 2px 8px rgba(0,0,0,.3);
    --overlay: rgba(0,0,0,.7);
    --chip-grey-bg: #1e2d44;
    --chip-grey-border: #2a3a54;
    --chip-grey-text: #999;
    --modal-shadow: 0 8px 48px rgba(0,0,0,.5);
    --grid-bg: #0f0f23;
    --cell-bg: #16213e;
    --header-bg: #0f1a2e;
    --header-text: #999;
    --fm-bg: #0f1a2e;
