  }
  .theme-toggle:hover { background: var(--surface-hover); }

  /* Overview charts */
  .overview-row {
    display: grid; grid-template-columns: 1fr 1fr;
    gap: 12px; margin-bottom: 14px;
  }
  .overview-card {
    background: var(--surface); border: 1px solid var(--border);
    border-radius: 10px; padding: 10px 14px;
  }
  .overview-card h3 { font-size: 0.78rem; font-weight: 600; color: var(--text-secondary); margin-bottom: 4px; }

  /* Summary bar */
  .summary-bar {
    display: flex; gap: 14px; margin-bottom: 14px; font-size: 0.8rem; align-items: center; flex-wrap: wrap;
  }
  .summary-bar span {
    padding: 5px 14px; border-radius: 16px; background: var(--surface);
    border: 1px solid var(--border); font-weight: 500;
  }
  .summary-bar strong { font-size: 1.15rem; margin-right: 2px; }

  /* Matrix */
  .matrix-wrap { overflow-x: auto; margin-bottom: 14px; }
  .matrix {
    display: grid; gap: 1px; background: var(--grid-bg);
    border-radius: 10px; overflow: hidden;
    box-shadow: var(--shadow); min-width: 960px;
  }
  .cell {
    background: var(--cell-bg); padding: 8px 10px; min-height: 50px;
    display: flex; flex-wrap: wrap; gap: 4px; align-content: start; align-items: start;
  }
  .cell-header {
    background: var(--header-bg); padding: 8px 6px;
    display: flex; align-items: center; justify-content: center;
    font-weight: 600; font-size: 0.73rem; color: var(--header-text); text-align: center;
  }
  .row-label {
    background: var(--header-bg); padding: 8px 10px;
    display: flex; align-items: center; gap: 6px; font-size: 0.74rem; font-weight: 600;
    white-space: nowrap;
  }

  /* Chips */
  .customer-chip {
    display: inline-flex; align-items: center; gap: 4px;
    padding: 3px 9px; border-radius: 13px; font-size: 0.71rem;
    cursor: pointer; border: 1px solid transparent; white-space: nowrap;
    transition: all .12s; user-select: none;
  }
  .customer-chip:hover { transform: translateY(-1px); box-shadow: 0 2px 8px rgba(0,0,0,.15); }
  .chip-red { background: #ffebee; border-color: #ffcdd2; color: #b71c1c; }
  .chip-yellow { background: #fff8e1; border-color: #ffecb3; color: #e65100; }
  .chip-grey { background: var(--chip-grey-bg); border-color: var(--chip-grey-border); color: var(--chip-grey-text); }
  .chip-dot { width: 5px; height: 5px; border-radius: 50%; flex-shrink: 0; }
