    --grid-bg: #e8e4dd;
    --cell-bg: #fefdfb;
    --header-bg: #f3f0ea;
    --header-text: #8c8880;
    --fm-bg: #f5f3ee;
    --fm-label: #8c8880;
    --chat-bg: #f5f3ee;
    --key-num-bg: #f3f0ea;
    --info-note-bg: #fef9e7;
    --info-note-text: #6b6658;
    --btn-border: #d5d0c8;
    --btn-hover: #f0ece5;
    --modal-border: #ebe6de;
    --dot-grey: #c5c0b8;
    --chip-grey-bg: #f2f0eb;
    --chip-grey-border: #e6e2db;
    --chip-grey-text: #8c8880;
    /* Chip colors - softened */
    --chip-red-bg: #fef5f5;
    --chip-red-border: #f5d5d5;
    --chip-red-text: #9b3a3a;
    --chip-yellow-bg: #fefcf5;
    --chip-yellow-border: #f0e8c8;
    --chip-yellow-text: #8b6914;
    --chip-dot-red: #d35f5f;
    --chip-dot-yellow: #c8942e;
  }
  [data-theme="dark"] {
    --bg: #26242a;
    --surface: #302e34;
    --surface-hover: #38363c;
    --border: #3e3c42;
