  .top-bar { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 12px; flex-wrap: wrap; gap: 8px; }
  h1 { font-size: 1.1rem; font-weight: 700; }
  .subtitle { color: var(--text-secondary); font-size: 0.75rem; margin-top: 1px; }
