const fs = require("fs");
const path = require("path");

const SRC = path.join(__dirname, "dashboard.html");
const DST = path.join(__dirname, "dashboard_v3.html");
const srcHtml = fs.readFileSync(SRC, "utf8");

// 提取 CARDS 数据
const cardsMatch = srcHtml.match(/var CARDS\s*=\s*(\[[\s\S]*?\]);/);
if (!cardsMatch) { console.error("CARDS not found"); process.exit(1); }
const CARDS = JSON.parse(cardsMatch[1]);
console.log(`Loaded ${CARDS.length} customer cards`);

// 统计
const urgencyCounts = { red: 0, yellow: 0, grey: 0, frozen: 0 };
const stageCounts = {};
const stageUrgency = {}; // stage -> {red, yellow, grey}
const stages = ["需求探索","报价已发","谈判中","待付款","待发货","在途","已签收","售后/返单"];
stages.forEach(s => { stageCounts[s] = 0; stageUrgency[s] = {red:0,yellow:0,grey:0}; });

CARDS.forEach(c => {
  const u = c.urgencyKey || "grey";
  urgencyCounts[u] = (urgencyCounts[u] || 0) + 1;

  // map stage to short form
  let stage = c.stage || "";
  if (stage === "已发货/在途") stage = "在途";
  if (!stages.includes(stage)) stage = "需求探索";
  stageCounts[stage] = (stageCounts[stage] || 0) + 1;
  if (stageUrgency[stage]) {
    stageUrgency[stage][u] = (stageUrgency[stage][u] || 0) + 1;
  }
});

// 构建矩阵：stage -> urgency -> [chips html]
const matrixHTML = {};
stages.forEach(s => { matrixHTML[s] = { red: [], yellow: [], grey: [] }; });

CARDS.forEach(c => {
  let stage = c.stage || "";
  if (stage === "已发货/在途") stage = "在途";
  if (!stages.includes(stage)) stage = "需求探索";

  const u = c.urgencyKey || "grey";
  if (u === "frozen") return; // frozen handled separately

  const tierBadge = c.tier === "S" ? '<span class="chip-tier-s">S</span>' :
                    c.tier === "A" ? '<span class="chip-tier-a">A</span>' : "";
  const statusBadge = c.statusBadge ? `<span class="chip-badge">${escHTML(c.statusBadge)}</span>` : "";
  const name = c.name || "?";

  const chipClass = u === "red" ? "chip-red" : u === "yellow" ? "chip-yellow" : "chip-grey";
  const dotClass = u === "red" ? "chip-dot-red" : u === "yellow" ? "chip-dot-yellow" : "chip-dot-grey";

  const chip = `<span class="customer-chip ${chipClass}" onclick="openModal('${c.cid}')"><span class="chip-dot ${dotClass}"></span>${escHTML(name)}${tierBadge}${statusBadge}</span>`;
  matrixHTML[stage][u].push(chip);
});

function escHTML(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// 构建矩阵grid
const matrixGridHTML = stages.map((stage, si) => {
  const redChips = matrixHTML[stage].red.join("");
  const yellowChips = matrixHTML[stage].yellow.join("");
  const greyChips = matrixHTML[stage].grey.join("");
  return `<div class="cell">${redChips + yellowChips + greyChips}</div>`;
}).join("\n");

// 构建 frozen chips
const frozenClients = CARDS.filter(c => (c.urgencyKey || "grey") === "frozen");
const frozenChipsHTML = frozenClients.map(c => {
  const name = c.name || "?";
  return `<span class="customer-chip chip-grey frozen-chip">${escHTML(name)}</span>`;
}).join("\n");

// ECharts 数据
const barData = stages.map(s => stageCounts[s] || 0);
const heatmapData = [];
stages.forEach((s, si) => {
  ["red","yellow","grey"].forEach((u, ui) => {
    const cnt = stageUrgency[s] ? (stageUrgency[s][u] || 0) : 0;
    if (cnt > 0) heatmapData.push([ui, si, cnt]);
  });
});

