  ${STAGES.map(s => `<div class="cell-header">${s}</div>`).join("")}

  <div class="row-label"><span class="chip-dot chip-dot-red"></span>🔴 需立即处理</div>
  ${STAGES.map(s => `<div class="cell" data-stage="${s}" data-urgency="red" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">${matrixData[s].red.map(d => chipHTML({...d, urgency:'red', stage:s})).join("")}</div>`).join("\n")}

  <div class="row-label"><span class="chip-dot chip-dot-yellow"></span>🟡 需定时关注</div>
  ${STAGES.map(s => `<div class="cell" data-stage="${s}" data-urgency="yellow" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">${matrixData[s].yellow.map(d => chipHTML({...d, urgency:'yellow', stage:s})).join("")}</div>`).join("\n")}

  <div class="row-label"><span class="chip-dot chip-dot-grey"></span>⚪ 正常流转</div>
  ${STAGES.map(s => `<div class="cell" data-stage="${s}" data-urgency="grey" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">${matrixData[s].grey.map(d => chipHTML({...d, urgency:'grey', stage:s})).join("")}</div>`).join("\n")}
</div>
</div>

<!-- 冷冻层 -->
<div class="frozen-section">
  <div class="frozen-toggle" onclick="toggleFrozen()" id="frozen-toggle">
    <span>❄️ 冷冻层 — ${urgencyCounts.frozen} 人 <span style="font-size:0.72rem;color:var(--text-secondary);">（>90天无互动，点击展开查看全部）</span></span>
    <span class="arrow">▶</span>
  </div>
  <div class="frozen-panel" id="frozen-panel">
    <input class="frozen-search" id="frozen-search" placeholder="搜索客户名或国家..." oninput="filterFrozen()">
    <div class="frozen-grid" id="frozen-grid"></div>
  </div>
</div>

<div class="legend">
  <span>🔴 需立即处理 = 我不动它就死</span>
  <span>🟡 需定时关注 = 业务推进但需提醒</span>
  <span>⚪ 正常流转 = 暂无行动信号</span>
  <span>❄️ 冷冻 = >90天无互动</span>
  <span style="margin-left:8px;">💡 拖拽客户 chip 到其他格子 = 改变阶段/紧急度</span>
</div>

<div class="overlay" id="overlay" onclick="if(event.target===this)closeModal()">
<div class="modal" id="modal"></div>
</div>

<div class="copy-toast" id="copy-toast">✅ 已复制</div>

<script>
var CARDS = ${CARDS_JSON};
var FROZEN = ${FROZEN_JSON};
var currentDragCid = null;

// ====== 主题切换 ======
function toggleTheme() {
  var body = document.body;
  var btn = document.getElementById("theme-btn");
  if (body.getAttribute("data-theme") === "dark") {
    body.setAttribute("data-theme", "light");
    btn.textContent = "🌙 暗色模式";
  } else {
    body.setAttribute("data-theme", "dark");
    btn.textContent = "☀️ 亮色模式";
  }
}

// ====== 拖拽 ======
function handleDragOver(e) {
  e.preventDefault();
  e.currentTarget.classList.add("drag-over");
}
function handleDragLeave(e) {
  e.currentTarget.classList.remove("drag-over");
}
function handleDrop(e) {
  e.preventDefault();
  e.currentTarget.classList.remove("drag-over");
  if (!currentDragCid) return;

  var cell = e.currentTarget;
  var newStage = cell.dataset.stage;
  var newUrgency = cell.dataset.urgency;

  // 更新 CARDS 数据
  var card = CARDS.find(function(c) { return c.cid === currentDragCid; });
  if (!card) return;

  // Map stage back
  var mappedStage = newStage === "在途" ? "已发货/在途" : newStage;
  card.stage = mappedStage;
  card.urgencyKey = newUrgency;

  // 更新 statusBadge
  if (newUrgency === "red" && !card.statusBadge) card.statusBadge = "刚拖入";
  if (newUrgency === "grey") card.statusBadge = "";

  // 移动 chip DOM
  var chip = document.querySelector('[data-cid="' + currentDragCid + '"]');
  if (chip) {
    chip.classList.remove("chip-red", "chip-yellow", "chip-grey");
    chip.classList.add("chip-" + newUrgency);
    chip.dataset.urgency = newUrgency;
    chip.dataset.stage = newStage;
    var dot = chip.querySelector(".chip-dot");
    if (dot) { dot.className = "chip-dot chip-dot-" + newUrgency; }
    cell.appendChild(chip);
  }

  currentDragCid = null;
  updateSummary();
}

document.addEventListener("dragstart", function(e) {
  var chip = e.target.closest(".customer-chip");
  if (!chip || chip.classList.contains("frozen-chip")) return;
  currentDragCid = chip.dataset.cid;
  chip.classList.add("dragging");
  e.dataTransfer.effectAllowed = "move";
  e.dataTransfer.setData("text/plain", chip.dataset.cid);
});

document.addEventListener("dragend", function(e) {
  var chip = e.target.closest(".customer-chip");
  if (chip) chip.classList.remove("dragging");
  currentDragCid = null;
});

function updateSummary() {
  var counts = {red:0, yellow:0, grey:0, frozen:0};
  CARDS.forEach(function(c) {
    var u = c.urgencyKey || "grey";
    counts[u] = (counts[u] || 0) + 1;
  });
  // Update summary bar (simplified - just update the strong tags)
  var spans = document.querySelectorAll(".summary-bar span strong");
  if (spans.length >= 4) {
    spans[0].textContent = counts.red;
    spans[1].textContent = counts.yellow;
    spans[2].textContent = counts.grey;
    spans[3].textContent = counts.frozen;
  }
}

// ====== 冷冻层 ======
function renderFrozen(filter) {
  var grid = document.getElementById("frozen-grid");
  var list = FROZEN;
  if (filter) {
    var q = filter.toLowerCase();
    list = FROZEN.filter(function(f) {
      return f.name.toLowerCase().includes(q) || f.country.toLowerCase().includes(q);
    });
  }
  var html = "";
  for (var i = 0; i < list.length; i++) {
    var f = list[i];
    var tb = ${JSON.stringify(tierColors)}[f.tier] || ${JSON.stringify(tierColors)}["C"];
    var sClass = f.tier === 'S' ? ' frozen-s' : '';
    html += '<div class="frozen-item' + sClass + '" onclick="openFrozenModal()" style="cursor:pointer;">' +
      '<span class="chip-tier" style="background:' + tb.bg + ';color:' + tb.color + ';flex-shrink:0;">' + f.tier + '</span>' +
      '<span style="flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;" title="' + esc(f.name) + '">' + (f.tier === 'S' ? '⭐' : '') + esc(f.name) + '</span>' +
      '<span style="font-size:0.68rem;color:var(--text-tertiary);flex-shrink:0;">' + esc(f.country) + '</span>' +
      '<span style="font-size:0.65rem;color:var(--text-secondary);flex-shrink:0;">' + (f.daysSince || "?") + 'd</span>' +
      '<button class="copy-btn" onclick="event.stopPropagation(); copyName(\'' + esc(f.name).replace(/'/g, "\\'") + '\', this)" title="复制名字">📋</button>' +
      '</div>';
  }
  if (list.length === 0) html = '<div style="padding:12px;color:var(--text-secondary);text-align:center;">无匹配结果</div>';
  grid.innerHTML = html;
}

function toggleFrozen() {
  var panel = document.getElementById("frozen-panel");
  var toggle = document.getElementById("frozen-toggle");
  var isOpen = panel.classList.contains("show");
  if (isOpen) {
    panel.classList.remove("show");
    toggle.classList.remove("open");
  } else {
    panel.classList.add("show");
    toggle.classList.add("open");
    if (!panel.dataset.rendered) {
      renderFrozen();
      panel.dataset.rendered = "1";
    }
  }
}

function filterFrozen() {
  var q = document.getElementById("frozen-search").value;
  renderFrozen(q);
}

function copyName(name, btn) {
  navigator.clipboard.writeText(name).then(function() {
    if (btn) { btn.classList.add("copied"); btn.textContent = "✓"; setTimeout(function() { btn.classList.remove("copied"); btn.textContent = "📋"; }, 1500); }
    var toast = document.getElementById("copy-toast");
    toast.textContent = "✅ 已复制: " + name;
    toast.classList.add("show");
    setTimeout(function() { toast.classList.remove("show"); }, 1800);
  });
}

// ====== Modal ======
function esc(s) {
  if (typeof s !== 'string') return String(s);
  return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

function deriveNextStep(c) {
  var steps = [];
  if (c.richDrivers && c.richDrivers.length) {
    for (var i=0; i<c.richDrivers.length; i++) {
      var dr = c.richDrivers[i];
      if (dr.level === 'red') steps.push('⚡ ' + dr.title + ' → 优先处理');
      else steps.push('📌 ' + dr.title);
    }
  }
  if (steps.length === 0) {
    switch (c.stage) {
      case '需求探索': steps.push('了解客户采购规模和目标市场，推送热卖款'); break;
      case '报价已发': steps.push('温和跟进报价反馈，确认是否有其他尺寸/面料需求'); break;
      case '谈判中': steps.push('推动下一步决策，确认打样/付款时间线'); break;
      case '待付款': steps.push('确认付款方式，发送PI'); break;
      case '待发货': steps.push('同步生产进度，拍照或视频给客户'); break;
      case '已发货/在途': steps.push('跟踪物流状态，到港前提醒清关'); break;
      case '已签收': steps.push('回访产品满意度，试探复购意向'); break;
      case '待返单': steps.push('同步新品/热卖款，争取返单'); break;
    }
  }
  if (c.daysSince !== null && c.daysSince > 30) {
    steps.push('⚠️ 已沉默' + c.daysSince + '天，考虑WhatsApp/电话触达');
  }
  return steps.join('\\n');
}

function openModal(cid) {
  var c = CARDS.find(function(x){ return x.cid === cid; });
  if (!c) return;

  // Lock body scroll
  document.body.classList.add("modal-open");

  var h = '';
  h += '<div class="modal-header"><h2>' + esc(c.name) + '</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';
  h += '<div class="modal-body">';

  h += '<div class="fm-grid">';
  var fields = [
    ['国家', c.countryCN || c.country],
    ['阶段', c.stage],
    ['等级', c.tier + '级'],
    ['最后联系', c.daysSince !== null ? c.daysSince + '天前' : '?']
  ];
  for (var i=0; i<fields.length; i++) {
    h += '<div class="fm-item"><div class="fm-label">' + fields[i][0] + '</div><div class="fm-value">' + esc(String(fields[i][1])) + '</div></div>';
  }
  if (c.firstContact) {
    h += '<div class="fm-item"><div class="fm-label">首次联系</div><div class="fm-value">' + c.firstContact + '</div></div>';
  }
  h += '</div>';

  if (c.richDrivers && c.richDrivers.length) {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="driver-list">';
    for (var j=0; j<c.richDrivers.length; j++) {
      var dr = c.richDrivers[j];
      var cls = dr.level === 'red' ? 'driver-item-red' : 'driver-item-yellow';
      var icon = dr.level === 'red' ? '🔴' : '🟡';
      h += '<div class="driver-item ' + cls + '"><span class="driver-icon">' + icon + '</span><div><strong>' + esc(dr.title) + '</strong><div style="color:var(--text-secondary);font-size:0.83em;margin-top:2px;">' + esc(dr.detail) + '</div></div></div>';
    }
    h += '</div></div>';
  } else if (c.urgencyKey === 'red') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">⚠️ 该客户标记为需立即处理，但未命中因子节奏天。</div></div>';
  } else if (c.urgencyKey === 'yellow') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">📌 该客户标记为需关注，可能刚联系过或等待客户行动中。</div></div>';
  } else if (c.urgencyKey !== 'frozen') {
    h += '<div class="section"><div class="section-title">📋 驱动因子</div><div class="info-note">无活跃因子。该客户在正常流转中，暂无行动信号。</div></div>';
  }

  if (c.chatLinesCN && c.chatLinesCN.length) {
    h += '<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">';
    for (var k=0; k<c.chatLinesCN.length; k++) {
      var cl = c.chatLinesCN[k];
      var whoClass = cl.who === '我方' ? 'chat-who-me' : 'chat-who-cust';
      h += '<div class="chat-line"><span class="chat-who ' + whoClass + '">' + esc(cl.who) + '</span><span class="chat-time">' + esc(cl.time) + '</span>' + esc(cl.action) + '</div>';
    }
    h += '</div></div>';
  } else if (c.chatLines && c.chatLines.length) {
    h += '<div class="section"><div class="section-title">💬 聊到哪了</div><div class="chat-snippet">';
    for (var kk=0; kk<c.chatLines.length; kk++) {
      var cl2 = c.chatLines[kk];
      var whoClass2 = cl2.who === 'me' ? 'chat-who-me' : 'chat-who-cust';
      h += '<div class="chat-line"><span class="chat-who ' + whoClass2 + '">' + (cl2.who === 'me' ? '我' : '客') + '</span><span class="chat-time">' + cl2.time + '</span>' + esc(cl2.text) + '</div>';
    }
    h += '</div></div>';
  }

  if (c.keyNums && c.keyNums.length) {
    h += '<div class="section"><div class="section-title">🔢 关键数字</div>';
    for (var m=0; m<c.keyNums.length; m++) {
      h += '<div class="key-num">' + esc(c.keyNums[m]) + '</div>';
    }
    h += '</div>';
  }

  if (c.nextStep) {
    h += '<div class="section"><div class="section-title">→ 下一步</div><div style="font-size:0.9em;line-height:1.7;white-space:pre-line">' + esc(c.nextStep) + '</div></div>';
  }

  if (!c.hasBrief && c.urgencyKey !== 'frozen') {
    var derivedStep = deriveNextStep(c);
    if (derivedStep) {
      h += '<div class="section"><div class="section-title">→ 建议动作</div><div style="font-size:0.9em;line-height:1.7;white-space:pre-line">' + derivedStep + '</div></div>';
    }
    h += '<div class="info-note" style="margin-top:12px;">📝 暂无深度状态卡。运行 /okki 深度分析获取完整聊天摘要和关键数字。</div>';
  }

  h += '</div>';
  h += '<div class="modal-footer"><button class="btn btn-primary">✏️ 起草回复</button><button class="btn">🔍 深度分析</button><button class="btn">✅ 标记已处理</button></div>';

  document.getElementById("modal").innerHTML = h;
  document.getElementById("overlay").classList.add("show");
}

function closeModal() {
  document.getElementById("overlay").classList.remove("show");
  document.body.classList.remove("modal-open");
}
document.addEventListener("keydown", function(e) {
  if (e.key === "Escape") closeModal();
});

// ====== 紧急度汇总弹窗 ======
function openUrgencyModal(urgency) {
  var urgencyNames = {red:"需立即处理", yellow:"需定时关注", grey:"正常流转", frozen:"冷冻"};
  var list = CARDS.filter(function(c) { return (c.urgencyKey || "grey") === urgency; });
  document.getElementById("modal-title").innerHTML = esc(urgencyNames[urgency] || urgency) + " — " + list.length + "人";
  var rows = "";
  for (var i = 0; i < list.length; i++) {
    var c = list[i];
    var tb = ${JSON.stringify(tierColors)}[c.tier] || ${JSON.stringify(tierColors)}["C"];
    rows += '<tr><td><span class="chip-tier" style="background:' + tb.bg + ';color:' + tb.color + ';font-size:0.6rem;padding:0 3px;border-radius:3px;font-weight:600;">' + c.tier + '</span> <strong style="cursor:pointer;color:var(--text);" onclick="event.stopPropagation();openModal(\'' + c.cid + '\')">' + esc(c.name) + '</strong></td><td style="text-align:center;">' + esc(c.countryCN || c.country || "") + '</td><td>' + esc(c.stage || "") + '</td><td style="text-align:center;">' + (c.daysSince !== null ? c.daysSince + "d" : "?") + '</td></tr>';
  }
  var h = '<div class="modal-header"><h2 id="modal-title">' + esc(urgencyNames[urgency] || urgency) + ' — ' + list.length + '人</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';
  h += '<div class="modal-body"><table style="width:100%;font-size:0.82rem;"><tr><th style="width:180px;">客户</th><th style="text-align:center;width:90px;">国家</th><th>阶段</th><th style="text-align:center;width:60px;">静默</th></tr>' + rows + '</table></div>';
  document.getElementById("modal").innerHTML = h;
  document.getElementById("overlay").classList.add("show");
  document.body.classList.add("modal-open");
}

// ====== 冷冻层全量弹窗 ======
function openFrozenModal() {
  var list = CARDS.filter(function(c) { return (c.urgencyKey || "grey") === "frozen"; });
  var rows = "";
  for (var i = 0; i < list.length; i++) {
    var c = list[i];
    var tb = ${JSON.stringify(tierColors)}[c.tier] || ${JSON.stringify(tierColors)}["C"];
    var star = c.tier === "S" ? "⭐" : "";
    rows += '<tr><td><span class="chip-tier" style="background:' + tb.bg + ';color:' + tb.color + ';font-size:0.6rem;padding:0 3px;border-radius:3px;font-weight:600;">' + c.tier + '</span> ' + star + ' <strong style="cursor:pointer;color:var(--text);" onclick="event.stopPropagation();openModal(\'' + c.cid + '\')">' + esc(c.name) + '</strong></td><td style="text-align:center;">' + esc(c.countryCN || c.country || "") + '</td><td>' + esc(c.stage || "") + '</td><td style="text-align:center;">' + (c.daysSince !== null ? c.daysSince + "d" : "?") + '</td><td><button class="copy-btn" onclick="event.stopPropagation();copyName(\'' + esc(c.name).replace(/'/g, "\\\\'") + '\', this)" title="复制名字">📋</button></td></tr>';
  }
  var h = '<div class="modal-header"><h2>❄️ 冷冻层 — ' + list.length + '人</h2><button class="modal-close" onclick="closeModal()">✕</button></div>';
  h += '<div class="modal-body"><p style="font-size:0.78rem;color:var(--text-secondary);margin-bottom:10px;">>90天无互动 | 点击客户名打开详情 | 点击 📋 复制名字</p><div style="max-height:60vh;overflow-y:auto;"><table style="width:100%;font-size:0.82rem;"><tr><th style="width:180px;">客户</th><th style="text-align:center;width:90px;">国家</th><th>最后阶段</th><th style="text-align:center;width:60px;">静默</th><th style="width:40px;"></th></tr>' + rows + '</table></div></div>';
  document.getElementById("modal").innerHTML = h;
  document.getElementById("overlay").classList.add("show");
  document.body.classList.add("modal-open");
}

// ====== ECharts ======
(function() {
  function initCharts() {
    var barEl = document.getElementById("chart-bar");
    var heatEl = document.getElementById("chart-heat");
    if (!barEl || !heatEl) return;
    if (typeof echarts === "undefined") { setTimeout(initCharts, 200); return; }

    var barChart = echarts.init(barEl);
  barChart.setOption({
    tooltip: { trigger: "axis" },
    grid: { left: 90, right: 30, top: 8, bottom: 20 },
    xAxis: { type: "value", axisLabel: { fontSize: 10 } },
    yAxis: { type: "category", data: ${JSON.stringify(STAGES)}, axisLabel: { fontSize: 10 } },
    series: [{
      type: "bar",
      data: ${JSON.stringify(barData)},
      itemStyle: { borderRadius: [0, 4, 4, 0], color: new echarts.graphic.LinearGradient(0,0,1,0,[{offset:0,color:"#5b8cbd"},{offset:1,color:"#8ab4d8"}]) },
      label: { show: true, position: "right", fontSize: 10 }
    }]
  });

  var heatChart = echarts.init(document.getElementById("chart-heat"));
  heatChart.setOption({
    tooltip: { formatter: function(p) { return ["🔴紧急","🟡关注","⚪正常"][p.value[0]] + " × " + ${JSON.stringify(STAGES)}[p.value[1]] + "<br/>" + p.value[2] + "人"; } },
    grid: { left: 8, right: 20, top: 20, bottom: 45 },
    xAxis: { type: "category", data: ["🔴紧急","🟡关注","⚪正常"], position: "top", axisLabel: { fontSize: 10 } },
    yAxis: { type: "category", data: ${JSON.stringify(STAGES)}, axisLabel: { fontSize: 10 } },
    visualMap: { min: 0, max: ${maxHeatVal}, calculable: false, orient: "horizontal", left: "center", bottom: 2, inRange: { color: ["#f7f5f1","#f5e6c8","#e8a850","#c06040"] } },
    series: [{ type: "heatmap", data: ${JSON.stringify(heatmapData)}, label: { show: true, fontSize: 9 }, emphasis: { itemStyle: { shadowBlur: 10, shadowColor: "rgba(0,0,0,.3)" } } }]
  });

  window.addEventListener("resize", function() { barChart.resize(); heatChart.resize(); });
}

initCharts();
})();
</script>

</body>
</html>`;

