input.content:
const fs = require("fs");
const html = fs.readFileSync("dashboard_v4.html", "utf8");
const m = html.match(/<script>\s*\n([\s\S]*?)\n\s*<\/script>/);
if (!m) { console.log("no script match"); process.exit(1); }

try {
  new Function(m[1]);
  console.log("JS syntax OK");
} catch (e) {
  const lines = m[1].split("\n");
  console.log("Error:", e.message);
  // Try to extract line number
  const stackMatch = (e.stack || "").match(/at eval.*?:(\d+):/);
  if (stackMatch) {
    const errLine = parseInt(stackMatch[1]);
    console.log("Near line", errLine);
    for (let i = Math.max(0, errLine - 3); i < Math.min(lines.length, errLine + 2); i++) {
      console.log((i + 1) + ": " + lines[i].substring(0, 200));
    }
  } else {
    console.log("Stack:", e.stack);
  }
}

