const fs = require("fs");
const html = fs.readFileSync("dashboard_v4.html", "utf8");
const m = html.match(/<script>\s*\n([\s\S]*?)\n\s*<\/script>/);
if (!m) { console.log("no match"); process.exit(1); }

// Write JS to temp file
fs.writeFileSync("_temp_js.js", m[1], "utf8");

// Use node --check
const { execSync } = require("child_process");
try {
  execSync('node --check "_temp_js.js"', { cwd: __dirname, stdio: "pipe" });
  console.log("JS syntax OK");
} catch (e) {
  const stderr = e.stderr ? e.stderr.toString() : "";
  console.log(stderr);
}

// Cleanup
try { fs.unlinkSync("_temp_js.js"); } catch (e) {}

