const cardsMatch = srcHtml.match(/var CARDS\s*=\s*(\[[\s\S]*?\]);/);
if (!cardsMatch) { console.error("CARDS not found"); process.exit(1); }
const CARDS = JSON.parse(cardsMatch[1]);
console.log(`Loaded ${CARDS.length} cards`);

// 确保每个客户都有 tier
CARDS.forEach(c => { if (!c.tier) c.tier = "C"; });

// 统计
const urgencyCounts = { red: 0, yellow: 0, grey: 0, frozen: 0 };
const stageUrgency = {};
const STAGES = ["需求探索","报价已发","谈判中","待付款","待发货","在途","已签收","售后/返单"];
STAGES.forEach(s => { stageUrgency[s] = {red:0,yellow:0,grey:0}; });

CARDS.forEach(c => {
  const u = c.urgencyKey || "grey";
  urgencyCounts[u] = (urgencyCounts[u] || 0) + 1;
  let s = c.stage === "已发货/在途" ? "在途" : (c.stage || "需求探索");
  if (!STAGES.includes(s)) s = "需求探索";
  if (u !== "frozen" && stageUrgency[s]) stageUrgency[s][u] = (stageUrgency[s][u] || 0) + 1;
});

function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

// Tier badge
const tierColors = {
  S: {bg:"#ffd700",color:"#5d4037",label:"S"},
  A: {bg:"#c8e6c9",color:"#2e7d32",label:"A"},
  B: {bg:"#e3f2fd",color:"#1565c0",label:"B"},
  C: {bg:"#f3e5f5",color:"#7b1fa2",label:"C"},
  D: {bg:"#fce4ec",color:"#c62828",label:"D"}
};

function tierBadgeHTML(t) {
  const tc = tierColors[t] || tierColors["C"];
  return `<span class="chip-tier" style="background:${tc.bg};color:${tc.color};">${tc.label}</span>`;
}

// 构建矩阵 chip HTML
const matrixData = {}; // stage -> urgency -> [{cid, name, tier, statusBadge}]
STAGES.forEach(s => { matrixData[s] = { red:[], yellow:[], grey:[] }; });

CARDS.forEach(c => {
  let s = c.stage === "已发货/在途" ? "在途" : (c.stage || "需求探索");
  if (!STAGES.includes(s)) s = "需求探索";
  const u = c.urgencyKey || "grey";
  if (u === "frozen") return;
  if (!matrixData[s]) matrixData[s] = { red:[], yellow:[], grey:[] };
  if (!matrixData[s][u]) matrixData[s][u] = [];
  matrixData[s][u].push({
    cid: c.cid,
    name: c.name || "?",
    tier: c.tier || "C",
    statusBadge: c.statusBadge || ""
  });
});

// 构建所有 frozen 数据（供冷冻层展开用）
const frozenClients = CARDS.filter(c => (c.urgencyKey || "grey") === "frozen")
  .map(c => ({
    cid: c.cid,
    name: c.name || "?",
    tier: c.tier || "C",
    country: c.countryCN || c.country || "",
    daysSince: c.daysSince,
    stage: c.stage || "",
    statusBadge: c.statusBadge || "",
    lastReason: c.lastReason || ""
  }));

const FROZEN_JSON = JSON.stringify(frozenClients);

function chipHTML(d) {
  const tb = tierBadgeHTML(d.tier);
  const sb = d.statusBadge ? `<span class="chip-badge">${esc(d.statusBadge)}</span>` : "";
  return `<span class="customer-chip chip-${d.urgency}" draggable="true" data-cid="${d.cid}" data-urgency="${d.urgency}" data-stage="${d.stage}"><span class="chip-dot chip-dot-${d.urgency}"></span>${esc(d.name)}${tb}${sb}</span>`;
}

// 热度图数据
const heatmapData = [];
STAGES.forEach((s, si) => {
  ["red","yellow","grey"].forEach((u, ui) => {
    const cnt = stageUrgency[s][u] || 0;
    if (cnt > 0) heatmapData.push([ui, si, cnt]);
  });
});
