  let s = c.stage === "已发货/在途" ? "在途" : (c.stage || "需求探索");
  if (!STAGES.includes(s)) s = "需求探索";
  if (u !== "frozen" && stageUrgency[s]) stageUrgency[s][u] = (stageUrgency[s][u] || 0) + 1;
});

function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

// Tier badge
